const rows = $input.all();
const first = rows[0] || {};
let bundle = first.json || {};
if (Array.isArray(bundle)) {
  bundle = bundle[0] || {};
}
if (bundle.schema !== 'botfucker.approved_actions.v1') {
  throw new Error(`Unexpected BotFucker approved action schema: ${bundle.schema || 'missing'}`);
}
if (bundle.safety_scope !== 'provider_action_export_only') {
  throw new Error('Approved action bundle safety_scope must be provider_action_export_only');
}
const processedRaw = $env.BOTFUCKER_PROCESSED_AUDIT_IDS || '';
const processedAuditIds = new Set(processedRaw.split(',').map((value) => value.trim()).filter(Boolean));
const actions = Array.isArray(bundle.actions) ? bundle.actions : [];
const validActions = actions.filter((action) => {
  if (!action.audit_id || processedAuditIds.has(action.audit_id)) return false;
  if (action.provider_execution !== 'not_performed') return false;
  if (action.safety_scope !== 'provider_action_export_only') return false;
  if (action.approved_action !== 'approve_warning') return false;
  return true;
});
return validActions.map((action) => ({
  json: {
    ...action,
    dry_run: true,
    bridge_status: 'validated_not_executed',
    dedupe_key: action.audit_id
  }
}));

return $input.all().map((item) => {
  const action = item.json || {};
  return {
    json: {
      dry_run: true,
      would_execute: action.approved_action,
      audit_id: action.audit_id,
      item_id: action.item_id,
      provider: action.provider || 'local',
      message_id: action.message_id || '',
      thread_id: action.thread_id || '',
      provider_execution: 'not_performed',
      bridge_status: 'dry_run_logged_only'
    }
  };
});
